                    var to = ParseCellAddress();
                    return SumRange(from, to);
                }

                return ResolveCellValue(from);
            }

            _position = save;
            var functionName = ParseName();
            SkipWhitespace();
            Expect('(');
            switch (functionName)
            {
                case "MIN":
                case "MAX":
